import hashlib
import uuid
from enum import Enum
from datetime import datetime

class InteractionType(Enum):
    LIKE = 1
    RATING = 2
    UPLOAD = 3
    SETTINGS_CHANGE = 4

class UserInteraction:
    def __init__(self, interaction_type, user_id, interaction_data):
        self.interaction_type = interaction_type
        self.user_id = hashlib.sha256(str(user_id).encode()).hexdigest()
        self.interaction_data = interaction_data
        self.timestamp = datetime.now()

class InteractionEngine:
    def __init__(self):
        self.interactions = {}

    def add_interaction(self, interaction):
        if interaction.user_id not in self.interactions:
            self.interactions[interaction.user_id] = []
        self.interactions[interaction.user_id].append(interaction)

    def get_interactions(self, user_id):
        user_id = hashlib.sha256(str(user_id).encode()).hexdigest()
        return self.interactions.get(user_id, [])

    def get_interaction_count(self, interaction_type):
        count = 0
        for interactions in self.interactions.values():
            count += sum(1 for interaction in interactions if interaction.interaction_type == interaction_type)
        return count

class RatingInteraction(UserInteraction):
    def __init__(self, user_id, rating):
        super().__init__(InteractionType.RATING, user_id, rating)

class LikeInteraction(UserInteraction):
    def __init__(self, user_id):
        super().__init__(InteractionType.LIKE, user_id, None)

class UploadInteraction(UserInteraction):
    def __init__(self, user_id, file_name):
        super().__init__(InteractionType.UPLOAD, user_id, file_name)

class SettingsChangeInteraction(UserInteraction):
    def __init__(self, user_id, settings):
        super().__init__(InteractionType.SETTINGS_CHANGE, user_id, settings)

engine = InteractionEngine()

def main():
    user_id = uuid.uuid4()
    engine.add_interaction(LikeInteraction(user_id))
    engine.add_interaction(RatingInteraction(user_id, 5))
    engine.add_interaction(UploadInteraction(user_id, "example.txt"))
    engine.add_interaction(SettingsChangeInteraction(user_id, {"theme": "dark"}))

    print(engine.get_interactions(user_id))
    print(engine.get_interaction_count(InteractionType.LIKE))

if __name__ == "__main__":
    main()

